Let \(T>0\), let \(V\in L^\infty(\R^n\times[0,T];\C)\), and let
\(u\in C([0,T];L^2(\R^n))\) satisfy, for every \(0\le s\le t\le T\),
\begin{equation}\label{eq:duhamel}
 u(t)=e^{i(t-s)\Delta}u(s)
 +i\int_s^t e^{i(t-r)\Delta}\bigl(V(r)u(r)\bigr)\,dr
 \quad\text{in }L^2(\R^n).
\end{equation}
Thus ``strong solution'' means precisely the Duhamel identity
\eqref{eq:duhamel}; no unmentioned spatial differentiability is assumed.
Put \(x_{1,+}=\max\{x_1,0\}\).  Assume that there is
\(c\in L^\infty([0,T];\C)\) such that
\begin{equation}\label{eq:tail-mod-scalar}
 \lim_{R\to\infty}\int_0^T
 \norm{V(\cdot,t)-c(t)}_{L^\infty(\{x_1>R\})}\,dt=0,
\end{equation}
and that, for some \(c_0,c_1>0\),
\begin{equation}\label{eq:endpoint-data}
 e^{c_0x_{1,+}^2}u(0),\qquad
 e^{c_1x_{1,+}^2}u(T)\in L^2(\R^n).
\end{equation}
If
\begin{equation}\label{eq:threshold}
 T^2c_0c_1>\frac1{16},
\end{equation}
then \(u\equiv0\) on \(\R^n\times[0,T]\).

Under the notation and domain assumptions of Lemma \ref{lem:SA-logconv},
let \(\gamma\in C^1([c,d])\) be positive and assume
\begin{equation}\label{eq:weighted-SA-lower}
 \langle(\gamma S_t+\gamma[S,A]+\gamma'S)f,f\rangle
 \ge-\psi(t)H(t)
\end{equation}
with \(\psi\ge0\).  Let \(T,M_\varepsilon\) be the zero-boundary
solutions
\begin{align*}
 (\gamma T')'&=-\psi,\\
 (\gamma M_\varepsilon')'
 &=-\gamma\frac{\norm E_2^2}{H+\varepsilon},
\end{align*}
and put
\[
 \Theta(t)=
 \frac{\int_t^d\gamma(s)^{-1}\,ds}
 {\int_c^d\gamma(s)^{-1}\,ds},\qquad
 N_\varepsilon=\int_c^d
 \frac{|\operatorname{Re}\langle E,f\rangle|}{H+\varepsilon}\,dt.
\]
Then
\begin{align}
 H(t)+\varepsilon
 \le{}&(H(c)+\varepsilon)^{\Theta(t)}
 (H(d)+\varepsilon)^{1-\Theta(t)}\notag\\
 &\times\exp\{2T(t)+M_\varepsilon(t)+2N_\varepsilon\}.
\label{eq:weighted-SA-output}
\end{align}

There is a numerical constant \(\Lambda<\infty\) with the following
property.  Let \(u\in C([0,1];L^2(\R^n))\) be a Duhamel solution of
\[
 \partial_tu=i(\Delta u+Vu),\qquad
 V\in L^\infty(\R^n\times[0,1]).
\]
Assume that the distributional derivative \(\partial_{x_1}u\) is locally
square integrable on \(\{x_1>1\}\times(0,1)\), and that, for some
\(\sigma>\Lambda\),
\begin{align}
 K_\sigma^2:={}&
 \sup_{0\le t\le1}\int_{\{x_1>1\}}
 e^{2\sigma x_1^2}|u(x,t)|^2\,dx\notag\\
 &+\int_{1/32}^{31/32}\int_{\{x_1>1\}}
 e^{2\sigma x_1^2}
 \bigl(|u|^2+|\partial_{x_1}u|^2\bigr)\,dx\,dt<\infty.
\label{eq:right-strip-hypothesis}
\end{align}
Then
\begin{equation}\label{eq:right-strip-conclusion}
 u=0\quad\text{almost everywhere on }
 \{x_1>2\}\times(3/8,5/8).
\end{equation}
The constant \(\Lambda\) is independent of \(n\), \(V\), \(u\), and
\(K_\sigma\).

Let \(J\subset\R\) be an open interval, let
\[
 u\in C(J;L^2(\R^n)),\qquad
 V\in L^\infty(\R^n\times J),
\]
and suppose
\[
 (i\partial_t+\Delta)u=-Vu
\]
in distributions.  Assume the following slab-local derivative condition:
for every bounded interval \(I\subset\R\) and every \(J_0\Subset J\),
\begin{equation}\label{eq:slab-local-derivative}
 \int_{J_0}\int_{I\times\R^{n-1}}
 |\partial_{x_1}u|^2\,dx\,dt<\infty.
\end{equation}
and, for some \(a\in\R\),
\begin{equation}\label{eq:lateral-initial-zero}
 u=0\quad\text{almost everywhere on }\{x_1>a\}\times J.
\end{equation}
If \(J'\Subset J\) and \(R>0\), then
\begin{equation}\label{eq:lateral-propagated-zero}
 u=0\quad\text{almost everywhere on }
 \{x_1>a-R/2\}\times J'.
\end{equation}
